#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,X; scanf("%d %d",&N,&X);
        int total=0, a;
        int arr[101];
        for(int i=0;i<N;i++){
            scanf("%d",&a);
            arr[i]=a;
            total+=a;
        }
        int K = total / X;
        if(K==0){
            printf("-1\n");
            continue;
        }
        int adequate=1;
        for(int i=0;i<N;i++){
            if( (total - arr[i]) / X >= K ){
                adequate=0; break;
            }
        }
        if(adequate) printf("%d\n",K); else printf("-1\n");
    }
    return 0;
}

